const express = require('express');
const session = require('express-session');
const redis = require('redis');
const client = redis.createClient();
const jwt = require('jsonwebtoken');

const app = express();

app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true,
  store: new session.RedisStore({ host: 'localhost', port: 6379 }),
}));

const refreshTokens = {};

client.on('connect', () => {
  console.log('Connected to Redis');
});

app.post('/token', (req, res) => {
  const { grant_type, code } = req.body;
  if (grant_type !== 'authorization_code') {
    return res.status(400).send({ error: 'invalid_grant' });
  }

  // Verify authorization code
  client.get(`code:${code}`, (err, data) => {
    if (!data) {
      return res.status(400).send({ error: 'invalid_grant' });
    }
    const clientId = JSON.parse(data).client_id;
    client.del(`code:${code}`);

    // Issue access token and refresh token
    const accessToken = jwt.sign({ sub: clientId }, process.env.SECRET_KEY, { expiresIn: '1h' });
    const refreshToken = jwt.sign({ sub: clientId }, process.env.SECRET_KEY, { expiresIn: '365d' });

    client.set(`refresh_token:${refreshToken}`, JSON.stringify({ client_id: clientId }), 'EX', 31536000);

    res.json({
      access_token: accessToken,
      refresh_token: refreshToken,
      token_type: 'Bearer',
      expires_in: 3600,
    });
  });
});

app.post('/token/refresh', (req, res) => {
  const { grant_type, refresh_token } = req.body;
  if (grant_type !== 'refresh_token') {
    return res.status(400).send({ error: 'invalid_grant' });
  }

  client.get(`refresh_token:${refreshToken}`, (err, data) => {
    if (!data) {
      return res.status(401).send({ error: 'invalid_grant' });
    }
    const clientId = JSON.parse(data).client_id;

    // Issue new access token
    const accessToken = jwt.sign({ sub: clientId }, process.env.SECRET_KEY, { expiresIn: '1h' });

    res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: 3600,
    });
  });
});

const port = 3000;
